const input = $input.first().json;
const body = input.body ?? input;

function pickFromObjects(keys) {
  const objects = [body, body.data, body.response, body.payload].filter(Boolean);
  for (const obj of objects) {
    for (const key of keys) {
      if (obj[key] !== undefined && obj[key] !== null && obj[key] !== '') {
        return String(obj[key]).trim();
      }
    }
  }
  return '';
}

const possibleFields = body.fields || body.data?.fields || body.response?.fields || body.payload?.fields || [];

function fieldByLabel(labelText) {
  if (!Array.isArray(possibleFields)) return '';
  const target = labelText.toLowerCase();

  const field = possibleFields.find((f) => {
    const label = String(f.label || f.question || f.title || f.name || f.key || '').toLowerCase();
    return label.includes(target);
  });

  if (!field) return '';

  const value = field.value ?? field.answer ?? field.text ?? field.response ?? '';

  if (Array.isArray(value)) return value.join(', ');
  if (typeof value === 'object' && value !== null) return JSON.stringify(value);
  return String(value).trim();
}

const firstName = pickFromObjects(['first_name', 'firstName', 'firstname']) || fieldByLabel('first name');
const lastName = pickFromObjects(['last_name', 'lastName', 'lastname']) || fieldByLabel('last name');
const email = pickFromObjects(['email', 'Email']) || fieldByLabel('email');
const phone = pickFromObjects(['phone', 'phone_number', 'phoneNumber', 'mobile']) || fieldByLabel('phone');
const companyName = pickFromObjects(['company_name', 'companyName', 'company', 'business_name', 'businessName']) || fieldByLabel('company');
const helpNeeded = pickFromObjects(['help_needed', 'message', 'description', 'need_help_with']) || fieldByLabel('what do you need help with');
const urgency = pickFromObjects(['urgency']) || fieldByLabel('urgent');
const referralSource = pickFromObjects(['referral_source', 'heard_about_us', 'source_detail']) || fieldByLabel('how did you hear');

const sourceResponseId = pickFromObjects([
  'event_id',
  'eventId',
  'response_id',
  'responseId',
  'submission_id',
  'submissionId',
  'id'
]);

const createdAt = pickFromObjects(['created_at', 'createdAt', 'submitted_at', 'submittedAt']);

let eventId = pickFromObjects(['event_id']);

if (!eventId && sourceResponseId) {
  eventId = `tally:${sourceResponseId}`;
}

if (!eventId && email && createdAt) {
  eventId = `fallback:${email}:${createdAt}`;
}

if (!eventId) {
  eventId = `manual:${Date.now()}`;
}

const normalized = {
  event_id: eventId,
  first_name: firstName,
  last_name: lastName,
  email,
  phone,
  company_name: companyName,
  source: body.source || 'tally',
  help_needed: helpNeeded,
  urgency,
  referral_source: referralSource,
  raw_payload: body,
  raw_payload_json: JSON.stringify(body)
};

return [{ json: normalized }];

const lead = $input.first().json;

const text = `${lead.message || ''} ${lead.company_name || ''}`.toLowerCase();

let intent = 'other';
if (text.includes('automat') || text.includes('workflow') || text.includes('follow-up') || text.includes('crm') || text.includes('missed call')) {
  intent = 'automation';
} else if (text.includes('website') || text.includes('webflow') || text.includes('landing page')) {
  intent = 'website';
} else if (text.includes('seo') || text.includes('google ranking') || text.includes('search')) {
  intent = 'seo';
}

const urgencyRaw = String(lead.urgency || '').toLowerCase();
const urgency = ['low', 'medium', 'high'].includes(urgencyRaw) ? urgencyRaw : 'medium';

let qualificationScore = 2;
if (intent === 'automation') qualificationScore += 1;
if (urgency === 'high') qualificationScore += 1;
if (lead.email) qualificationScore += 1;
if (qualificationScore > 5) qualificationScore = 5;

let recommendedAction = 'nurture';
if (qualificationScore >= 4) recommendedAction = 'call';
else if (qualificationScore === 3) recommendedAction = 'email';
else if (qualificationScore < 2) recommendedAction = 'disqualify';

const classification = {
  intent,
  urgency,
  company_size_estimate: 'unknown',
  qualification_score: qualificationScore,
  summary: `${lead.first_name || 'This lead'} from ${lead.company_name || 'an unknown company'} asked for help with: ${lead.message || 'No message provided'}. CRM outcome: ${lead.crm_outcome}.`,
  recommended_action: recommendedAction
};

return [{
  json: {
    ...lead,
    classification,
    classification_json: JSON.stringify(classification)
  }
}];

